import React, { useState, useEffect } from 'react';

function TestimonialCarousel() {
  const testimonials = [
    {
      id: 1,
      text: 'This is a great product!',
      author: 'John Doe',
    },
    {
      id: 2,
      text: 'I love this product!',
      author: 'Jane Doe',
    },
    {
      id: 3,
      text: 'This product is amazing!',
      author: 'Bob Smith',
    },
  ];

  const [currentTestimonial, setCurrentTestimonial] = useState(0);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setCurrentTestimonial((prev) => (prev + 1) % testimonials.length);
    }, 3000);

    return () => clearInterval(intervalId);
  }, [testimonials.length]);

  return (
    <div className="bg-white p-4 md:p-6 lg:p-8 flex flex-col items-center justify-center">
      <h2 className="text-3xl font-bold text-zinc-900 mb-4">
        What Our Customers Say
      </h2>
      <div className="flex flex-col items-center justify-center">
        <p className="text-lg text-zinc-900 mb-4">
          {testimonials[currentTestimonial].text}
        </p>
        <p className="text-zinc-900">
          - {testimonials[currentTestimonial].author}
        </p>
      </div>
      <div className="flex space-x-4 mt-4">
        {testimonials.map((testimonial, index) => (
          <button
            key={testimonial.id}
            className={`bg-zinc-200 p-2 rounded-md ${
              currentTestimonial === index ? 'bg-zinc-900 text-white' : ''
            }`}
            onClick={() => setCurrentTestimonial(index)}
          >
            {index + 1}
          </button>
        ))}
      </div>
    </div>
  );
}

export default TestimonialCarousel;

